#!/usr/bin/env python3
"""
Bug #2411: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'row_reduce_mul_transpose'], ['broadcast', 'prelu'], ['broadcast', 'acos_unary'], ['normalization', 'reduce_min_last'], ['layout', 'transpose_matmul_transpose'], ['normalization', 'reduce_logsum_last']]
Dependencies: numpy jax
Run         : python unique_2411.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])
_w2 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256, 256])
_w4 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("6f12833a"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_rrmt_mean = jnp.mean(x, axis=(-1,), keepdims=True)
    n0_rrmt_sub = x - n0_rrmt_mean
    n0_rrmt_scl = n0_rrmt_sub * n0_rrmt_sub
    n0_rrmt_tp = jnp.transpose(n0_rrmt_scl, [0, 2, 1])
    n0_rrmt_out = jnp.transpose(n0_rrmt_tp, [0, 2, 1])
    n100_prl_pos = jnp.maximum(n0_rrmt_out, np.float32(0.0))
    n100_prl_neg = jnp.minimum(n0_rrmt_out, _w1)
    n100_prl_sl = n100_prl_neg * _w0
    n100_prl_out = n100_prl_pos + n100_prl_sl
    n200_acos_th = jnp.tanh(n100_prl_out)
    n200_acos_act = jnp.arccos(n200_acos_th)
    n200_acos_out = n200_acos_act * n100_prl_out
    n300_redu_red = jnp.min(n200_acos_out, axis=(-1,), keepdims=True)
    n300_redu_z = n200_acos_out * _w2
    n300_redu_out = n300_redu_z + n300_redu_red
    n400_tmmt_tr1 = jnp.transpose(n300_redu_out, [0, 2, 1])
    n400_tmmt_tr2 = jnp.transpose(n400_tmmt_tr1, [0, 2, 1])
    n400_tmmt_mm = jnp.matmul(n400_tmmt_tr2, _w3)
    n400_tmmt_out = jnp.transpose(n400_tmmt_mm, [0, 2, 1])
    n400_tmmt_final = jnp.transpose(n400_tmmt_out, [0, 2, 1])
    n500_redu_abs = jnp.abs(n400_tmmt_final)
    n500_redu_sh = n500_redu_abs + _w5
    n500_redu_red = jnp.log(jnp.sum(n500_redu_sh, axis=(-1,), keepdims=True))
    n500_redu_z = n400_tmmt_final * _w4
    n500_redu_out = n500_redu_z + n500_redu_red
    return jnp.asarray(n500_redu_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
